local nR = me:RandomInt(1, 30)
local nI = me:RandomInt(1, 5)
if me:GetFlag(600) == 0 then
	me:AddMsg(XT("[NAME]感到血脉引与自身产生共鸣，但因尚处筑基之境，无法彻底释放其潜能。"));
	me:SetFlag(600, 1);
